import React, { useState } from 'react';
import { db, auth } from './firebase';
import { collection, query, where, getDocs, addDoc, writeBatch, doc } from "firebase/firestore";
import { signOut } from "firebase/auth";

const MedAcePro = ({ user }) => {
  const [view, setView] = useState('hub'); // hub, practice, admin
    const [activeSubject, setActiveSubject] = useState(null);
      const [questions, setQuestions] = useState([]);
        const [loading, setLoading] = useState(false);
          const [selectedAnswers, setSelectedAnswers] = useState({});
            const [csvText, setCsvText] = useState(""); // For Admin Upload

              // 1. APNI EMAIL YAHAN LIKHO
                const mySecretEmail = "medace.admin@gmail.com".toLowerCase();
                  const isAdmin = user && user.email.toLowerCase() === mySecretEmail;

                    const subjects = [
                        { id: 'ana', name: 'Anatomy', icon: '🦴', color: 'bg-orange-50 text-orange-500' },
                            { id: 'phy', name: 'Physiology', icon: '🫀', color: 'bg-red-50 text-red-500' },
                                { id: 'path', name: 'Pathology', icon: '🔬', color: 'bg-purple-50 text-purple-500' },
                                    { id: 'pharma', name: 'Pharmacology', icon: '💊', color: 'bg-green-50 text-green-500' },
                                        { id: 'micro', name: 'Microbiology', icon: '🧫', color: 'bg-blue-50 text-blue-500' }
                                          ];

                                            // --- FUNCTIONS ---
                                              const fetchQuestions = async (subjectName) => {
                                                  setLoading(true);
                                                      setQuestions([]);
                                                          setSelectedAnswers({});
                                                              try {
                                                                    const q = query(collection(db, "questions"), where("subject", "==", subjectName.trim()));
                                                                          const snap = await getDocs(q);
                                                                                const data = snap.docs.map(doc => ({ id: doc.id, ...doc.data() }));
                                                                                      setQuestions(data);
                                                                                          } catch (e) { console.error(e); }
                                                                                              setLoading(false);
                                                                                                };

                                                                                                  const handleBulkUpload = async () => {
                                                                                                      if (!csvText) return alert("Bhai, pehle data toh daal!");
                                                                                                          setLoading(true);
                                                                                                              try {
                                                                                                                    const lines = csvText.split('\n').filter(line => line.trim() !== "");
                                                                                                                          const batch = writeBatch(db);
                                                                                                                                
                                                                                                                                      lines.forEach(line => {
                                                                                                                                              const [subject, unit, questionText, a, b, c, d, correctAnswer] = line.split(',');
                                                                                                                                                      const newDocRef = doc(collection(db, "questions"));
                                                                                                                                                              batch.set(newDocRef, {
                                                                                                                                                                        subject: subject.trim(),
                                                                                                                                                                                  unit: unit.trim(),
                                                                                                                                                                                            questionText: questionText.trim(),
                                                                                                                                                                                                      options: { A: a.trim(), B: b.trim(), C: c.trim(), D: d.trim() },
                                                                                                                                                                                                                correctAnswer: correctAnswer.trim().toUpperCase(),
                                                                                                                                                                                                                          createdAt: new Date()
                                                                                                                                                                                                                                  });
                                                                                                                                                                                                                                        });

                                                                                                                                                                                                                                              await batch.commit();
                                                                                                                                                                                                                                                    alert("Success! Saare sawal upload ho gaye.");
                                                                                                                                                                                                                                                          setCsvText("");
                                                                                                                                                                                                                                                              } catch (e) { alert("Upload fail: " + e.message); }
                                                                                                                                                                                                                                                                  setLoading(false);
                                                                                                                                                                                                                                                                    };

                                                                                                                                                                                                                                                                      // --- VIEW: ADMIN PANEL ---
                                                                                                                                                                                                                                                                        if (view === 'admin') {
                                                                                                                                                                                                                                                                            return (
                                                                                                                                                                                                                                                                                  <div className="min-h-screen bg-gray-50">
                                                                                                                                                                                                                                                                                          <div className="p-4 bg-white border-b flex items-center justify-between sticky top-0 z-50">
                                                                                                                                                                                                                                                                                                    <button onClick={() => setView('hub')} className="font-bold text-blue-600">← BACK</button>
                                                                                                                                                                                                                                                                                                              <h2 className="font-black text-gray-800">ADMIN CONTROL</h2>
                                                                                                                                                                                                                                                                                                                        <div className="w-10"></div>
                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                        <div className="p-6 max-w-2xl mx-auto">
                                                                                                                                                                                                                                                                                                                                                  <div className="bg-white p-6 rounded-[2rem] shadow-sm border">
                                                                                                                                                                                                                                                                                                                                                              <h3 className="font-black mb-2 text-gray-800 uppercase text-sm">Bulk CSV Upload</h3>
                                                                                                                                                                                                                                                                                                                                                                          <p className="text-[10px] text-gray-400 mb-4 font-bold uppercase">Format: Subject, Unit, Question, A, B, C, D, Answer</p>
                                                                                                                                                                                                                                                                                                                                                                                      <textarea 
                                                                                                                                                                                                                                                                                                                                                                                                    value={csvText}
                                                                                                                                                                                                                                                                                                                                                                                                                  onChange={(e) => setCsvText(e.target.value)}
                                                                                                                                                                                                                                                                                                                                                                                                                                placeholder="Anatomy, Upper Limb, Name the bone..., Humerus, Radius, Ulna, Femur, A"
                                                                                                                                                                                                                                                                                                                                                                                                                                              className="w-full h-64 p-4 bg-gray-50 border rounded-2xl text-sm mb-4"
                                                                                                                                                                                                                                                                                                                                                                                                                                                          />
                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <button 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    onClick={handleBulkUpload}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  disabled={loading}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                className="w-full bg-blue-600 text-white font-black py-4 rounded-2xl active:scale-95 transition-all disabled:opacity-50"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          {loading ? "UPLOADING..." : "PUSH DATA TO CLOUD"}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      // --- VIEW: PRACTICE PAGE ---
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        if (view === 'practice') {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="min-h-screen bg-white">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <div className="p-4 bg-white border-b flex items-center justify-between sticky top-0 z-50 shadow-sm">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <button onClick={() => setView('hub')} className="w-10 h-10 flex items-center justify-center bg-gray-100 rounded-full text-blue-600 font-bold">←</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <h2 className="text-xl font-black text-gray-800">{activeSubject.name}</h2>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="w-10"></div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div className="p-4 space-y-6 max-w-2xl mx-auto pb-24">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  {loading ? (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div className="text-center py-20 font-bold text-blue-500 animate-pulse text-sm uppercase tracking-widest">Fetching PYQs...</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ) : questions.map((q, i) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    <div key={q.id} className="bg-white p-6 rounded-[2.5rem] shadow-sm border border-gray-100">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <div className="flex justify-between items-center mb-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <span className="text-[10px] font-black bg-blue-50 text-blue-500 px-3 py-1 rounded-full uppercase tracking-tighter tracking-widest">Q{i + 1}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <span className="text-[10px] font-bold text-gray-300 uppercase">{q.unit}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <h3 className="text-lg font-bold text-gray-800 mb-6 leading-tight">{q.questionText}</h3>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="grid gap-3">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            {Object.entries(q.options).map(([k, v]) => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <button 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  key={k} 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      onClick={() => !selectedAnswers[q.id] && setSelectedAnswers(p => ({...p, [q.id]: k}))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          className={`w-full text-left p-4 rounded-2xl border-2 transition-all flex items-center ${
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                selectedAnswers[q.id] ? (k === q.correctAnswer ? 'border-green-500 bg-green-50' : selectedAnswers[q.id] === k ? 'border-red-500 bg-red-50' : 'border-gray-50 opacity-50') : 'border-gray-100'
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }`}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <span className={`w-8 h-8 flex items-center justify-center rounded-lg font-black mr-4 ${selectedAnswers[q.id] === k ? (k === q.correctAnswer ? 'bg-green-500 text-white' : 'bg-red-500 text-white') : (k === q.correctAnswer && selectedAnswers[q.id] ? 'bg-green-500 text-white' : 'bg-gray-100 text-gray-400')}`}>{k}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <span className="font-semibold">{v}</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // --- VIEW: DASHBOARD (HUB) ---
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            return (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                <div className="p-6 bg-gray-50 min-h-screen pb-20">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="flex justify-between items-start mb-12 mt-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <h1 className="text-4xl font-black text-blue-900 leading-none tracking-tighter">medACE</h1>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  <span className="text-blue-500 font-bold text-[10px] uppercase tracking-[0.4em] mt-1 block">PRO EDITION</span>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            <div className="mt-4 flex items-center gap-4">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         <p className="text-gray-400 text-[10px] font-black uppercase tracking-widest">User: {user?.displayName?.split(' ')[0]}</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <button onClick={() => signOut(auth)} className="text-[10px] font-black text-red-400 uppercase tracking-widest underline">Logout</button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                {isAdmin && (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          <button 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      onClick={() => setView('admin')}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  className="w-12 h-12 bg-white shadow-xl shadow-blue-100 rounded-2xl flex items-center justify-center text-xl border border-blue-50 active:scale-90 transition-all"
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            >
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        ⚙️
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  </button>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          )}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                </div>

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      <div className="grid gap-4 max-w-md mx-auto">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              {subjects.map(sub => (
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        <div key={sub.id} onClick={() => { setActiveSubject(sub); setView('practice'); fetchQuestions(sub.name); }} 
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       className="bg-white p-5 rounded-[2.5rem] shadow-sm flex items-center gap-5 cursor-pointer active:scale-95 transition-all border border-transparent hover:border-blue-100 group">
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   <div className={`w-16 h-16 rounded-[1.8rem] flex items-center justify-center text-3xl shadow-inner transition-transform group-hover:scale-110 ${sub.color}`}>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 {sub.icon}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         <div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                       <div className="font-black text-xl text-gray-800">{sub.name}</div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                     <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-0.5">Start Practicing →</p>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                 </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                           </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                   ))}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                         </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             </div>
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               );
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               };

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                               export default MedAcePro;
